static int handle_get_ftp_config(struct mg_connection* conn, void* cbdata) {
    char user_id_str[32];
    if (!get_param(conn, "user_id", user_id_str, sizeof(user_id_str))) {
        send_json(conn, 400, "Missing user_id", NULL);
        return 200;
    }

    int user_id = atoi(user_id_str);
    FtpConfig config;
    int rc = db_ftp_config_get_by_user(user_id, &config);

    if (rc == 0) {
        char data[512];
        snprintf(data, sizeof(data), "{\"host\":\"%s\",\"port\":%d,\"user\":\"%s\",\"path\":\"%s\"}",
            config.ftp_host, config.ftp_port, config.ftp_user, config.ftp_path);
        send_json(conn, 200, "OK", data);
    } else {
        send_json(conn, 404, "FTP config not found", NULL);
    }
    return 200;
}

static const char* get_param(struct mg_connection* conn, const char* name, char* buf, size_t buf_size) {
    const struct mg_request_info* ri = mg_get_request_info(conn);

    // 先尝试从 query_string 获取 (GET 请求)
    if (ri->query_string) {
        int len = mg_get_var(ri->query_string, strlen(ri->query_string), name, buf, buf_size);
        if (len > 0) return buf;
    }

    // 尝试从 POST 数据获取
    // 读取 POST 数据
    char post_data[MAX_POST_DATA];
    int post_len = mg_read(conn, post_data, sizeof(post_data) - 1);
    if (post_len > 0) {
        post_data[post_len] = '\0';
        int len = mg_get_var(post_data, post_len, name, buf, buf_size);
        if (len > 0) return buf;
    }

    return NULL;
}

int db_ftp_config_get_by_user(int user_id, FtpConfig* config) {
    if (g_db == NULL) return -1;

    sqlite3_stmt* stmt;
    int rc = sqlite3_prepare_v2(g_db, SELECT_FTP_BY_USER, -1, &stmt, NULL);
    if (rc != SQLITE_OK) return -1;

    sqlite3_bind_int(stmt, 1, user_id);

    if (sqlite3_step(stmt) == SQLITE_ROW) {
        config->id = sqlite3_column_int(stmt, 0);
        config->user_id = sqlite3_column_int(stmt, 1);

        if (sqlite3_column_text(stmt, 2)) {
            strncpy(config->ftp_host, (const char*)sqlite3_column_text(stmt, 2), 255);
        } else {
            config->ftp_host[0] = '\0';
        }

        config->ftp_port = sqlite3_column_int(stmt, 3);

        if (sqlite3_column_text(stmt, 4)) {
            strncpy(config->ftp_user, (const char*)sqlite3_column_text(stmt, 4), 127);
        } else {
            config->ftp_user[0] = '\0';
        }

        if (sqlite3_column_text(stmt, 5)) {
            strncpy(config->ftp_pass, (const char*)sqlite3_column_text(stmt, 5), 127);
        } else {
            config->ftp_pass[0] = '\0';
        }

        if (sqlite3_column_text(stmt, 6)) {
            strncpy(config->ftp_path, (const char*)sqlite3_column_text(stmt, 6), 255);
        } else {
            config->ftp_path[0] = '\0';
        }

static int handle_get_ftp_config(const rpc_request_t* request, rpc_response_t* response) {
    FtpConfig config;
    int rc = db_ftp_config_get_by_user(request->user_id, &config);
    if (rc != 0) {
        response->status = RPC_ERROR_NOT_FOUND;
        snprintf(response->message, sizeof(response->message), "FTP config not found");
        return -1;
    }

    response->status = RPC_SUCCESS;
    response->ftp_port = config.ftp_port;
    strncpy(response->ftp_host, config.ftp_host, sizeof(response->ftp_host) - 1);
    strncpy(response->ftp_user, config.ftp_user, sizeof(response->ftp_user) - 1);
    strncpy(response->ftp_path, config.ftp_path, sizeof(response->ftp_path) - 1);
    snprintf(response->message, sizeof(response->message), "OK");
    return 0;
}
